mapper.update:
UPDATE file_metadata
   SET status = 'DELETE_FAILED',
       updated_at = #{updatedAt},
       updated_by = #{updatedBy},
       version = version + 1
 WHERE tenant_id = #{tenantId}
   AND id = #{id}
   AND deleted = 0
   AND version = #{version}
   AND status = 'AVAILABLE'

mapper.select:
SELECT *
  FROM file_metadata
 WHERE tenant_id = #{tenantId}
   AND id = #{id}
   AND deleted = 0
   AND status = 'AVAILABLE'

SELECT *
  FROM file_metadata
 WHERE tenant_id = #{tenantId}
   AND id = #{id}
   AND deleted = 0
   AND status IN ('AVAILABLE', 'DELETE_FAILED')

mapper.sql:
WHERE tenant_id = #{tenantId}
  AND deleted = 0

    AND original_filename LIKE CONCAT('%', #{filename}, '%')


    AND content_type = #{contentType}


    AND created_at >= #{uploadedFrom}


    AND created_at <= #{uploadedTo}

mapper.delete:
DELETE FROM file_metadata
 WHERE tenant_id = #{tenantId}
   AND id = #{id}
   AND deleted = 0
   AND status = 'UPLOADING'
